BEGIN
  IF AD_isTriggerEnabled()='N' THEN RETURN;
  END IF;
	-- Verifica si existen líneas relacionadas
	  IF EXISTS (
	    SELECT 1
	    FROM mrp_salesforecast
	    WHERE mrp_salesforecast_id = :OLD.mrp_salesforecast_id
	  ) THEN
			RAISE_APPLICATION_ERROR(-20000, '@ssmrp_msgdelete_trg@');
	  END IF;
END SSMRP_DELETE_SALESFORECAST_TRG
